import React, { useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { updateMe } from '../services/api';
import toast from 'react-hot-toast';
import './Auth.css';

export default function Profile() {
  const { user, loginUser } = useAuth();
  const [name, setName] = useState(user?.name || '');
  const [loading, setLoading] = useState(false);

  const submit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const res = await updateMe({ name });
      loginUser(localStorage.getItem('token'), res.data);
      toast.success('Profile updated!');
    } catch { toast.error('Update failed.'); }
    finally { setLoading(false); }
  };

  return (
    <div className="auth-page">
      <div className="auth-card card fade-up">
        <div className="auth-logo">⚕ MediMind</div>
        <h2 className="auth-title">My Profile</h2>
        <p className="auth-sub">{user?.email} · {user?.role?.replace('_', ' ')}</p>

        <form onSubmit={submit}>
          <div className="form-group">
            <label>Full Name</label>
            <input className="form-input" value={name} onChange={(e) => setName(e.target.value)} required />
          </div>
          <div className="form-group">
            <label>Email</label>
            <input className="form-input" value={user?.email} disabled style={{ opacity: 0.6 }} />
          </div>
          <div className="form-group">
            <label>Role</label>
            <input className="form-input" value={user?.role?.replace('_', ' ')} disabled style={{ opacity: 0.6, textTransform: 'capitalize' }} />
          </div>
          <button type="submit" className="btn btn-primary auth-btn" disabled={loading}>
            {loading ? 'Saving...' : 'Save Changes'}
          </button>
        </form>
      </div>
    </div>
  );
}
